+    api.registerGatewayMethod("demo.file", async () => ({ ok: true }));
+  },
+};
+JS
+
+  node dist/index.js plugins install "file:$file_pack_dir/package"
+  node dist/index.js plugins list --json > /tmp/plugins4.json
+
+  node - <<'"'"'NODE'"'"'
+const fs = require("node:fs");
+
